VALUES
  ('social-worker-moex-05840', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若廖教授完成資料分析後，驗證了其所提出的「女性社工人員的倫理兩難決斷力較男性來得高」這個研 究假設。但有不少男性社工人員質疑量表中將進行倫理決策的頻率、時間及影響人數等題目納入，忽略 了男性社工人員比較少有機會從事第一線的實務工作，因而較少參與在倫理兩難的決策中。請問這些男 性社工人員質疑的是這個量表的：', '["鑑別度（discrimination）", "效度（validity）", "信度（reliability）", "精確度（precision） 情況：假想某篇論文是以《中國時報》、《聯合報》、《自由時報》、《蘋果日報》於最近二十年間（即1996 ～2015 年），針對新住民進行報導的 19,738 則新聞為母全體；作者先將母全體的每篇報導以時間順序 排列，形成一個抽樣架構後，以每六則取一則的方式抽出3,289篇新聞報導作為樣本；之後針對樣本與 研究者所建立的類目表進行比對與歸類，進而整理出臺灣主流媒體所型塑的新住民形象。請依上述資料 回答下列第17題至第19題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05841', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請問此研究的分析單位是：', '["1996年至2015年的每一年", "每一則對新住民的報導", "《中國時報》、《聯合報》、《自由時報》、《蘋果日報》", "新住民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05842', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '這篇論文所採用的抽樣方法是：', '["集叢抽樣", "分層隨機抽樣", "系統隨機抽樣", "簡單隨機抽樣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05843', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '這篇論文所採用的研究方法是：', '["次級資料分析法", "調查研究法", "內容分析法", "歷史比較分析法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05844', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '從抽樣的理論來看，方便抽樣（convenience sampling）最大的缺點在於：', '["回收率通常會很低", "樣本代表性不足", "作答者會相互影響", "樣本數經常會不足 情況：假想某政府單位委託民間民意調查機構，以電腦隨機撥號的方式，進行「臺灣應否逐步廢除死刑以符合 國際人權公約的準則」之電話民調。該調查指稱有效樣本數為3,757份，具有95%的信賴水準（confidence level）。請依上述資料回答下列第21題至第22題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05845', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若該民調想更精準地掌握民意，希望達到99%的信賴水準，請問該民調公司該怎麼做？', '["樣本數不變，修改問卷內容，使題意更淺顯易懂", "樣本數不變，改採分層隨機抽樣進行抽樣，以增加樣本代表性", "增加有效樣本數到10,500人", "針對同樣的樣本改採面訪，以減少電話訪問的機構效應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05846', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若在調查前幾天，剛好發生街頭隨機殺人事件，且經媒體大幅報導；顯然此街頭隨機殺人事件及其後續 的討論可能會影響民意調查的結果。請問影響該民意調查效度的因素為何？', '["歷史（history）", "選取（selection）", "成熟（maturation）", "統計迴歸（statistical regression）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05847', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那個統計方法可用自變項的變化來預測依變項的變化？', '["簡單迴歸", "皮爾遜積差相關", "卡方檢定", "單因子變異數分析"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05848', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者想進行「失智症主要照顧者的照顧壓力」的研究，其中有關「壓力來源」這一題，研究者羅列 出16個壓力情境供填答者勾選，且可以複選。請問在此研究中，「壓力來源」是屬於下列何種測量尺度？', '["名目（nominal）測量尺度", "次序（ordinal）測量尺度", "等距（interval）測量尺度", "比例（ratio）測量尺度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05849', 'social-worker', 'social-worker-moex-105-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若研究者設計一個問題是：「請問您照顧的失智症長者是    歲」。這個問題最大的缺失是什麼？', '["使用了引導式的問法，易引起受訪者的從眾反應", "使用了雙重否定的問法，使受訪者需花很多時間來做判斷", "同時問了一個以上的問題，使受訪者產生困惑而無法正確掌握題意", "無法涵蓋受訪者所有可能的情境，若受訪者同時照顧兩位以上的長者則無法正確回答 ⎛觀察值−平均數⎞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9f7d5685624f", "answer_pdf_sha1": "b2e59b626294", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
